import org.apache.flink.api.common.functions.MapFunction;
import org.apache.flink.streaming.api.datastream.DataStream;
import org.apache.flink.streaming.api.environment.StreamExecutionEnvironment;

public class InventoryAdjustmentJob {

    public static void main(String[] args) throws Exception {
        final StreamExecutionEnvironment env = StreamExecutionEnvironment.getExecutionEnvironment();

        // Set checkpointing mode
        env.enableCheckpointing(5000, CheckpointingMode.EXACTLY_ONCE);

        // Set time characteristic to event-time processing
        env.setStreamTimeCharacteristic(TimeCharacteristic.EventTime);

        // Configure restart strategy
        env.getConfig().setRestartStrategy(RestartStrategies.fixedDelayRestart(
            3, // Number of restart attempts
            Time.seconds(10) // Delay between restarts in seconds
        ));

        DataStream<Order> orderStream = env.addSource(new KafkaConsumer<>("order_created", Order.class))
            .map(new MapFunction<String, Order>() {
                @Override
                public Order map(String value) throws Exception {
                    return objectMapper.readValue(value, Order.class);
                }
            });

        // Process the stream and adjust inventory levels
        orderStream.map(new InventoryAdjustmentFunction())
            .addSink(new KafkaProducer<>("inventory_adjusted", Order.class));

        env.execute("Inventory Adjustment Job");
    }

    public static class InventoryAdjustmentFunction implements MapFunction<Order, Order> {
        @Override
        public Order map(Order order) throws Exception {
            // Adjust inventory levels based on the order
            adjustInventory(order);

            return order;
        }

        private void adjustInventory(Order order) {
            // Business logic for adjusting inventory levels
        }
    }

    public static class KafkaConsumer<T> extends RichParallelSourceFunction<T> {
        @Override
        public void run(SourceContext<T> ctx) throws Exception {
            Properties props = new Properties();
            props.setProperty("bootstrap.servers", "localhost:9092");
            props.setProperty("group.id", "inventory-group");

            KafkaConsumer<String, String> consumer = new KafkaConsumer<>(props);
            consumer.subscribe(Arrays.asList("order_created"));

            while (true) {
                ConsumerRecords<String, String> records = consumer.poll(Duration.ofMillis(100));
                for (ConsumerRecord<String, String> record : records) {
                    T order = objectMapper.readValue(record.value(), Order.class);

                    ctx.collect(order);  // Emit processed order to downstream services

                    if (ctx.isCanceled()) break;
                }
            }
        }

        @Override
        public void cancel() {
            consumer.close();
        }
    }

    public static class KafkaProducer<T> implements SinkFunction<T> {
        private final String topic;

        public KafkaProducer(String topic, Class<T> clazz) {
            this.topic = topic;
        }

        @Override
        public void invoke(T value, Context context) throws Exception {
            kafkaTemplate.send(topic, objectMapper.writeValueAsString(value));
        }
    }
}
```

