                    return true;
                } catch (Exception e) {
                    System.err.println("Failed to process order: " + e.getMessage());
                    // Abort the transaction on failure
                    return false;
                }
            });

            // Acknowledge offset only after successful processing and committing the transaction
            acknowledgment.acknowledge();
        } catch (Exception e) {
