    public KafkaMessageListenerContainer<String, Order> kafkaListenerContainerFactory() {
        ContainerProperties containerProps = new ContainerProperties("order_created");
        containerProps.setGroupId("inventory-group");

        return new KafkaMessageListenerContainer<>(kafkaConsumerFactory(), containerProps);
    }

